const item = $input.first();

// 1. Получаем грязный текст от Gemini
const rawText = item.json.content?.parts?.[0]?.text || "";

// 2. Очищаем от Markdown разметки
const cleanJson = rawText.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();

try {
  // 3. Превращаем в объект
  const siteConfig = JSON.parse(cleanJson);

  // 4. Возвращаем результат
  // Мы сохраняем config в отдельное поле, чтобы он был доступен везде
  return {
    json: {
      // ...item.json, // Оставляем старые данные (Query, URL и т.д.)
      siteConfig: siteConfig
    }
  };
} catch (error) {
  throw new Error(`Ошибка парсинга JSON от Gemini: ${error.message}`);
}

// Получаем первый входной элемент (данные сайта из БД)
const item = $input.first();
const json = item.json;

// 1. Парсим конфиг сайта
let config;
if (typeof json.site_config === 'string') {
    try {
        config = JSON.parse(json.site_config);
    } catch (e) {
        throw new Error("Ошибка парсинга site_config: " + e.message);
    }
} else {
    config = json.site_config;
}

if (!config || !config.pages_structure) {
    throw new Error("В site_config не найдена структура страниц (pages_structure).");
}

// 2. Получаем и чистим код (удаляем ```html и прочее)
const cleanCode = (str, lang) => {
    if (!str) return "";
    const regex = new RegExp(`^\`\`\`${lang}\\s*|\\s*\`\`\`$`, 'gi');
    return str.replace(regex, '').trim();
};

const layout = cleanCode(json.layout_html, 'html');
const css = cleanCode(json.css_code, 'css');
const js = cleanCode(json.js_code, 'javascript');

// 3. Формируем массив задач (Fan Out)
// Мы берем массив страниц из конфига и превращаем каждую в отдельный item для n8n
return config.pages_structure.map(page => ({
    json: {
        page_data: page,           // Данные конкретной страницы (title, slug, type)
        global_config: config,     // Глобальный конфиг (нужен писателю для контекста)
        layout: layout,            // Шаблон HTML
        css: css,                  // CSS код
        js: js                     // JS код
    }
}));

// Получаем ответ от Gemini (текущий ввод)
const geminiInput = $input.first();

// --- 1. ВОССТАНОВЛЕНИЕ ДАННЫХ (FIX DATA LOSS) ---
// Нам нужны данные, которые были ДО Gemini. Мы берем их из узла SplitPagesLoop.
// Внутри цикла n8n автоматически сопоставляет текущий item.
const sourceItem = $('SplitPagesLoop').item; 

if (!sourceItem) {
    throw new Error("Не удалось найти исходные данные в SplitPagesLoop");
}

const layout = sourceItem.json.layout;
const pageData = sourceItem.json.page_data;
const config = sourceItem.json.global_config;

// --- 2. ПАРСИНГ ОТВЕТА GEMINI ---
let rawResponse = 
    geminiInput.json.content?.parts?.[0]?.text || 
    geminiInput.json.output || 
    (typeof geminiInput.json === 'string' ? geminiInput.json : JSON.stringify(geminiInput.json));

let pageContent = {};
try {
    // Чистим JSON от markdown
    const cleanJsonString = String(rawResponse).replace(/^```json\s*|\s*```$/gi, '').trim();
    pageContent = JSON.parse(cleanJsonString);
} catch (e) {
    // Фоллбэк
    pageContent = {
        content_html: rawResponse,
        meta_description: "" 
    };
}

// --- 3. ПОДГОТОВКА META ---
let metaDesc = pageContent.meta_description;
if (!metaDesc) {
    metaDesc = config.site_identity.meta_description_template.replace('[Page Title]', pageData.title);
}

// --- 4. СБОРКА HTML ---
// Используем replace с функцией для защиты от спецсимволов в контенте ($& и т.д.)
let finalHtml = layout.replace('{CONTENT}', () => pageContent.content_html);

finalHtml = finalHtml
    .replace(/{TITLE}/g, pageData.title)
    .replace(/{DESCRIPTION}/g, metaDesc)
    .replace('{CANONICAL}', `https://${config.site_identity.domain || 'site.com'}/${pageData.slug === 'index' ? '' : pageData.slug + '/'}`)
    .replace(/{LANG}/g, $('BaseData').first() ? `${$('BaseData').first().json.Lang}_${$('BaseData').first().json.Country}` : 'sv_SE');

// --- 5. ИМЯ ФАЙЛА ---
let fileName;
if (pageData.type === 'system' && pageData.slug === '404') {
    fileName = '404.html';
} else if (pageData.slug === 'index') {
    fileName = 'index.html';
} else {
    fileName = `${pageData.slug}/index.html`;
}

return {
    json: {
        fileName: fileName,
        slug: pageData.slug,
        title: pageData.title,
        status: 'generated'
    },
    binary: {
        data: {
            data: Buffer.from(finalHtml).toString('base64'),
            mimeType: 'text/html',
            fileName: fileName
        }
    }
};

const item = $input.first();
const config = item.json.siteConfig || JSON.parse(item.json.site_config); // Берем из JSON или из базы
const domain = $('GetDomainForConfig').first().json.url; // Или ваш источник домена
// 1. Достаем имена файлов программно (100% точность)
const getAsset = (id) => {
  const asset = config.assets_plan.find(a => a.id === id);
  return asset ? asset.filename : null;
};

const logoFile = getAsset('logo');
const faviconFile = getAsset('favicon');
const heroFile = getAsset('hero_bg');
const ogFile = getAsset('og_image');

// 2. Готовим список ссылок для Sitemap
// (у нас есть структура страниц в конфиге)
const sitemapLinks = config.pages_structure.map(page => {
  const slug = page.slug === 'index' ? '' : page.slug + '/';
  // Исключаем 404 из сайтмэпа
  if (page.type === 'system') return null;

  return {
    loc: `https://${domain}/${slug}`,
    lastmod: new Date().toISOString().split('T')[0],
    changefreq: 'monthly',
    priority: page.slug === 'index' ? '1.0' : '0.8'
  };
}).filter(Boolean); // Убираем null

return {
  json: {
    // ...item.json,
    domain: domain,
    // Передаем имена файлов отдельно, чтобы LLM не ошибся
    real_filenames: {
        logo: logoFile,
        favicon: faviconFile,
        hero: heroFile,
        og: ogFile
    },
    sitemap_data: sitemapLinks
  }
};

const item = $input.first();
const links = item.json.sitemap_data;

// Начало XML
let xml = '<?xml version="1.0" encoding="UTF-8"?>\n';
xml += '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n';

// Цикл по ссылкам
links.forEach(link => {
    xml += '  <url>\n';
    xml += `    <loc>${link.loc}</loc>\n`;
    xml += `    <lastmod>${link.lastmod}</lastmod>\n`;
    xml += `    <priority>${link.priority}</priority>\n`;
    xml += '  </url>\n';
});

// Конец XML
xml += '</urlset>';

return {
    json: {
        // ...item.json,
        // Добавляем результаты предыдущего шага (Gemini) и этот XML
        tech_files: {
            ...item.json.tech_files, // Если Gemini вернул объект в поле tech_files (нужно распарсить)
            sitemap_xml: xml
        }
    }
};

const crypto = require('crypto');

function normalizeDomain(rawUrl) {
  if (!rawUrl) return '';
  let u = String(rawUrl).trim().toLowerCase();

  // чтобы URL() не падал, если протокола нет
  if (!/^https?:\/\//.test(u)) u = 'https://' + u;

  try {
    const parsed = new URL(u);
    return parsed.hostname.replace(/^www\./, '').toLowerCase();
  } catch (e) {
    // fallback
    return u
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .split('/')[0]
      .trim()
      .toLowerCase();
  }
}

return $input.all().map(item => {
  const raw = item.json.URL ?? item.json.url ?? '';
  const normalized_domain = normalizeDomain(raw);
  const site_id = crypto.createHash('sha1').update(normalized_domain).digest('hex');

  return {
    json: {
      ...item.json,
      normalized_domain,
      site_id,
    },
  };
});
